steps.solution:
def fake_server(request):
    if request["method"] == "tools/list":
        return {
            "tools": [
                {"name": "add", "description": "Add two numbers"},
                {"name": "echo", "description": "Echo a string"},
            ]
        }
    if request["method"] == "tools/call":
        params = request["params"]
        name = params["name"]
        args = params["arguments"]
        if name == "add":
            total = args["a"] + args["b"]
            return {"content": [{"type": "text", "text": str(total)}], "isError": False}
        if name == "echo":
            return {"content": [{"type": "text", "text": args["text"]}], "isError": False}
        return {"content": [{"type": "text", "text": "unknown tool"}], "isError": True}

def list_tool_names(server):
    response = server({"method": "tools/list"})
    return [t["name"] for t in response["tools"]]

def run_tool(server, name, arguments):
    request = {"method": "tools/call", "params": {"name": name, "arguments": arguments}}
    result = server(request)
    if result["isError"]:
        return "error"
    return result["content"][0]["text"]

